                case AppTextVariant.numHeadingSemibold2xl:
                    return theme.textStyle.numHeadingSemibold2xl;
            
                case AppTextVariant.numHeadingSemibold3xl:
                    return theme.textStyle.numHeadingSemibold3xl;
            
                case AppTextVariant.numHeadingSemiboldLg:
                    return theme.textStyle.numHeadingSemiboldLg;
            
                case AppTextVariant.numHeadingSemiboldMd:
                    return theme.textStyle.numHeadingSemiboldMd;
            
                case AppTextVariant.numHeadingSemiboldXl:
                    return theme.textStyle.numHeadingSemiboldXl;
            }
        } ();
        return Text(text, style: style.merge(this.style).copyWith(color: color));
    }
}



